import java.io.IOException;
import java.io.PrintWriter;
import org.apache.commons.text.StringEscapeUtils;

public class XssSecureCode {
    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Properly handling user input by encoding it before outputting to the web page
        try {
            PrintWriter out = new PrintWriter("index.html");
            out.println("<html><body>");
            out.println("<h1>Welcome, " + StringEscapeUtils.escapeHtml4(userInput) + "</h1>");
            out.println("</body></html>");
            out.close();
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
